//! Build script for `firewood-storage`.
//!
//! Generates `$OUT_DIR/area_sizes.rs`, which is `include!`d by
//! `src/nodestore/primitives.rs`. The generated file contains:
//!
//! - `NUM_AREA_SIZES` — the count of valid block sizes.
//! - `AREA_SIZES` — the sorted array of valid block sizes (in bytes).
//! - `AREA_SIZE_NAMES` — string representations of each size, used by
//!   [`index_name`](../src/nodestore/primitives.rs).
//! - `AREA_SIZES_HASH` — a SHA-256 hash of the raw `AREA_SIZES` bytes,
//!   written into the on-disk [`NodeStoreHeader`] so that a database created
//!   with one set of sizes cannot be opened with a different set.
//!
//! To change the set of valid block sizes, edit the `area_sizes![…]` invocation
//! below and rebuild. The hash will be recomputed automatically.

/// Declares the set of valid area (block) sizes used by `NodeStore`.
///
/// Expands into three parallel constants derived from the same list of
/// expressions, keeping them in sync without manual duplication:
///
/// - `NUM_AREA_SIZES` — the number of sizes.
/// - `AREA_SIZES` — the evaluated numeric values (`[u64; N]`).
/// - `AREA_EXPRS` — the source expressions as strings (`[&str; N]`), used to
///   duplicate the original expression in the generated code for transparency.
macro_rules! area_sizes {
    ($( $size:expr ),* $(,)?) => {
        const NUM_AREA_SIZES: usize = area_sizes!(@count $($size,)*);
        const AREA_SIZES: [u64; NUM_AREA_SIZES] = [$( $size ),*];
        const AREA_EXPRS: [&str; NUM_AREA_SIZES] = [ $( stringify!($size) ),* ];
    };
    (@count) => {
        0
    };
    (@count $head:expr, $($rest:expr,)*) => {
        1 + area_sizes!(@count $($rest,)*)
    }
}

area_sizes![
    16, // Min block size
    32,
    64,
    96,
    128,
    256,
    512,
    768,
    1024,
    1024 << 1,
    1024 << 2,
    1024 << 3,
    1024 << 4,
    1024 << 5,
    1024 << 6,
    1024 << 7,
    1024 << 8,
    1024 << 9,
    1024 << 10,
    1024 << 11,
    1024 << 12,
    1024 << 13,
    1024 << 14,
];

fn main() {
    println!("cargo:rerun-if-changed=build.rs");
    let out_dir = std::env::var("OUT_DIR").expect("OUT_DIR not set");
    let dest_path = std::path::Path::new(&out_dir).join("area_sizes.rs");
    let contents = generate_area_sizes_rs().expect("Failed to generate area_sizes.rs");
    std::fs::write(dest_path, contents).expect("Failed to write area_sizes.rs");
}

/// Generates the contents of `area_sizes.rs`.
///
/// Computes the SHA-256 hash of the raw `AREA_SIZES` bytes (using
/// [`bytemuck::bytes_of`] for a deterministic, native-endianness byte
/// representation) and emits the four constants described in the module doc.
fn generate_area_sizes_rs() -> Result<String, std::fmt::Error> {
    use std::fmt::Write;
    let area_sizes_bytes = bytemuck::bytes_of(&AREA_SIZES);
    let area_sizes_hash: [u8; 32] = <sha2::Sha256 as sha2::Digest>::digest(area_sizes_bytes).into();

    let mut output = String::new();
    writeln!(
        output,
        "// This file is generated by build.rs. Do not edit manually.

const NUM_AREA_SIZES: usize = {NUM_AREA_SIZES};

/// [`NodeStore`] divides the linear store into blocks of different sizes. This array
/// contains every valid block size, in ascending order.
///
/// [`NodeStore`]: crate::nodestore::NodeStore
const AREA_SIZES: [u64; NUM_AREA_SIZES] = [",
    )?;

    for (size, expr) in std::iter::zip(AREA_SIZES, AREA_EXPRS) {
        writeln!(output, "    {expr}, // {size} bytes")?;
    }

    writeln!(
        output,
        "];

/// Human-readable names for each area size, used by [`index_name`].
const AREA_SIZE_NAMES: [&str; NUM_AREA_SIZES] = [",
    )?;
    for size in AREA_SIZES {
        writeln!(output, "    \"{size}\",")?;
    }

    writeln!(
        output,
        "];

/// A SHA-256 hash of the raw `AREA_SIZES` bytes, used for integrity checks.
pub(crate) const AREA_SIZES_HASH: [u8; 32] = [",
    )?;

    for byte in area_sizes_hash {
        writeln!(output, "    {byte:#04x},")?;
    }

    writeln!(output, "];")?;

    Ok(output)
}
